"""
Parameterized generator for GH637_actions_1116.

Source PR:    https://github.com/ansys/actions/pull/1116
Source Issue: https://github.com/ansys/actions/issues/1115

Seed varies: renames 'action' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH637_actions_1116'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH637_actions_1116'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('action', 'action' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH637_actions_1116',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'ansys/actions',
                "pr_number": 1116,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/ansys/actions/pull/1116",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            '.github/dependabot.yml': 'version: 2\nupdates:\n  - package-ecosystem: "pip"\n    directories:\n      - "/requirements"\n      - "/check-vulnerabilities"\n    schedule:\n      interval: "daily"\n    cooldown:\n      default-days: 7\n      include:\n        - "*"  # Include all dependencies in cooldown\n      exclude:\n        - "ansys-sphinx-theme"\n    commit-message:\n      prefix: "build(pip)"\n    labels:\n      - "dependencies:requirements"\n\n  - package-ecosystem: "github-actions"\n    directories:\n      - ".github/workflows"\n      - "_doc-build-linux"\n      - "_doc-build-windows"\n      - "_doc-gen-canonical"\n      - "_doc-gen-robots"\n      - "_doc-gen-sitemap"\n      - "_doc-gen-versions-page"\n      - "_logging"\n      - "_pr-doc-clean"\n      - "_pr-doc-deployment"\n      - "_release-pypi"\n      - "_setup-python"\n      - "build-ci-wheels"\n      - "build-library"\n      - "build-wheelhouse"\n      - "check-actions-security"\n      - "check-environment-approval"\n      - "check-licenses"\n      - "check-pr-title"\n      - "check-vulnerabilities"\n      - "code-style"\n      - "doc-build"\n      - "doc-changelog"\n      - "doc-deploy-changelog"\n      - "doc-deploy-dev"\n      - "doc-deploy-pr"\n      - "doc-deploy-stable"\n      - "docker-style"\n      - "doc-style"\n      - "hk-automerge-prs"\n      - "hk-package-clean-except"\n      - "hk-package-clean-untagged"\n      - "release-github"\n      - "release-pypi-private"\n      - "release-pypi-public"\n      - "release-pypi-test"\n      - "tests-pytest"\n    schedule:\n      interval: "weekly"\n      day: "wednesday"\n    cooldown:\n      default-days: 7\n      include:\n        - "*"  # Include all dependencies in cooldown\n    commit-message:\n      prefix: "build(actions)"\n    labels:\n      - "dependencies:ci"\n    groups:\n      # Actions related to this repo\'s CI/CD\n      cicd-actions:\n        patterns:\n          - "micnncim/action-label-syncer"\n      # Github actions that are used in our composite actions\n      github-actions:\n        patterns:\n          - "actions/*"\n      # Actions associated to our style composite actions\n      style-related-actions:\n        patterns:\n          - "amannn/action-semantic-pull-request"\n          - "jbergstroem/hadolint-gh-action"\n      # Group dedicated to vale due to the use of a release branch (reviewdog20)\n      vale-action:\n        patterns:\n          - "errata-ai/vale-action"\n      # Actions associated to our documentation composite actions\n      doc-related-actions:\n        patterns:\n          - "awalsh128/cache-apt-pkgs-action"\n          - "quarto-dev/quarto-actions/setup"\n          - "peaceiris/actions-gh-pages"\n          - "peter-evans/create-or-update-comment"\n      # Actions associated to our tests composite actions\n      test-related-actions:\n        patterns:\n          - "docker/login-action"\n      # Actions associated to our build composite actions\n      build-related-actions:\n        patterns:\n          - "docker/setup-qemu-action"\n          - "pypa/cibuildwheel"\n          - "astral-sh/setup-uv"\n      # Actions associated to our release composite actions\n      release-related-actions:\n        patterns:\n          - "pypa/gh-action-pypi-publish"\n          - "softprops/action-gh-release"\n      # Missed non ansys actions that should by assigned to a group\n      must-be-assigned-actions:\n        patterns:\n          - peter-evans/find-comment\n          - pyvista/setup-headless-display-action\n          - vimtor/action-zip\n          - dependabot/fetch-metadata\n        exclude-patterns:\n          - "ansys/actions*"\n',
            'hk-package-clean-except/action.yml': '# Copyright (C) 2022 - 2026 ANSYS, Inc. and/or its affiliates.\r\n# SPDX-License-Identifier: MIT\r\n#\r\n#\r\n# Permission is hereby granted, free of charge, to any person obtaining a copy\r\n# of this software and associated documentation files (the "Software"), to deal\r\n# in the Software without restriction, including without limitation the rights\r\n# to use, copy, modify, merge, publish, distribute, sublicense, and/or sell\r\n# copies of the Software, and to permit persons to whom the Software is\r\n# furnished to do so, subject to the following conditions:\r\n#\r\n# The above copyright notice and this permission notice shall be included in all\r\n# copies or substantial portions of the Software.\r\n#\r\n# THE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR\r\n# IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,\r\n# FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE\r\n# AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER\r\n# LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,\r\n# OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN THE\r\n# SOFTWARE.\r\n\r\nname: "Clean all package versions except certain tags."\r\ndescription: |\r\n  "Action cleaning up all package versions published at ghcr.io except for certain tags."\r\n\r\n  .. note::\r\n\r\n    If an image matched by ``tags-kept`` has multiple tags (which are potentially not in the ``tags-kept`` list),\r\n    then the entire image (with all its tags) will be kept.\r\n\r\ninputs:\r\n  package-name:\r\n    description: "Package name."\r\n    required: true\r\n    type: string\r\n  token:\r\n    description: "Token with package deletion permissions."\r\n    required: true\r\n    type: string\r\n  tags-kept:\r\n    description: "Tags to be kept. Pass them as a list: e.g. \'latest, latest-unstable\'."\r\n    required: true\r\n    type: string\r\n  package-org:\r\n    description: "Organization at which packages are published."\r\n    required: false\r\n    default: \'ansys\'\r\n    type: string\r\n  allow-last-days:\r\n    description: "Avoid removing the last N days images: e.g. \'2\'."\r\n    required: false\r\n    default: \'\'\r\n    type: string\r\n  python-version:\r\n    description: \'Desired Python version.\'\r\n    default: \'3.11\'\r\n    required: false\r\n    type: string\r\n  use-uv:\r\n    description: |\r\n      Whether to use uv as the default package manager instead of pip. Default value is ``true``.\r\n    default: true\r\n    required: false\r\n    type: boolean\r\n\r\nruns:\r\n  using: "composite"\r\n  steps:\r\n\r\n    - name: "Set up Python ${{ inputs.python-version }}"\r\n      uses: ansys/actions/_setup-python@main\r\n      with:\r\n        python-version: ${{ inputs.python-version }}\r\n        use-cache: false\r\n        provision-uv: ${{ inputs.use-uv }}\r\n        prune-uv-cache: true\r\n\r\n    - name: "Install ghapi"\r\n      shell: bash\r\n      env:\r\n        INSTALL_COMMAND: ${{ inputs.use-uv == \'true\' && \'uv pip install --no-managed-python --system\' || \'python -m pip install\' }}\r\n      run: |\r\n\r\n        ${INSTALL_COMMAND} --upgrade pip\r\n        ${INSTALL_COMMAND} ghapi\r\n\r\n    - name: "Declare Python script"\r\n      shell: bash\r\n      run: |\r\n        cat > clean-except.py << \'EOF\'\r\n\r\n        from datetime import datetime, timedelta\r\n        import os\r\n\r\n        from ghapi.all import GhApi\r\n        from ghapi.core import print_summary\r\n        from ghapi.page import paged\r\n\r\n        PACKAGE_TIME_FORMAT = "%Y-%m-%dT%H:%M:%SZ"\r\n\r\n        org_str = os.environ.get("PACKAGE_ORG")\r\n        pck_str = os.environ.get("PACKAGE_NAME")\r\n        last_days_str = os.environ.get("ALLOW_LAST_DAYS")\r\n        valid_tags_str = os.environ.get("VALID_TAGS_STR")\r\n\r\n        last_days = int(last_days_str) if last_days_str != "" else None\r\n        valid_tags = [x.strip() for x in valid_tags_str.split(",")]\r\n\r\n        api = GhApi(debug=print_summary, token=os.getenv("PACKAGE_DELETION_TOKEN"))\r\n\r\n        if last_days:\r\n            delete_before_date = datetime.now() - timedelta(days=last_days)\r\n\r\n        paged_packages = paged(\r\n            api.packages.get_all_package_versions_for_package_owned_by_org,\r\n            org=org_str,\r\n            package_name=pck_str,\r\n            package_type="container",\r\n            state="active",\r\n            per_page=100,\r\n        )\r\n\r\n        # Loop over all pages\r\n        for page in paged_packages:\r\n            for package in page:\r\n                # If keeping last days is requested, then check\r\n                if (\r\n                    last_days\r\n                    and datetime.strptime(package.created_at, PACKAGE_TIME_FORMAT).timestamp()\r\n                    > delete_before_date.timestamp()\r\n                ):\r\n                    continue\r\n\r\n                # Check if the given package has valid tags\r\n                package_tags = package.metadata.container.tags\r\n                delete = True\r\n                for tag in package_tags:\r\n                    if tag in valid_tags:\r\n                        delete = False\r\n                        break\r\n\r\n                # In case it should, delete it\r\n                if delete:\r\n                    print(f"Deleting package: {package}")\r\n                    api.packages.delete_package_version_for_org(\r\n                        org=org_str,\r\n                        package_name=pck_str,\r\n                        package_type="container",\r\n                        package_version_id=package["id"],\r\n                    )\r\n\r\n        EOF\r\n        cat clean-except.py\r\n\r\n    - name: "Run package cleanup"\r\n      shell: bash\r\n      env:\r\n        ALLOW_LAST_DAYS: ${{ inputs.allow-last-days }}\r\n        PACKAGE_ORG: ${{ inputs.package-org }}\r\n        PACKAGE_NAME: ${{ inputs.package-name }}\r\n        PACKAGE_DELETION_TOKEN: ${{ inputs.token }}\r\n        VALID_TAGS_STR: ${{ inputs.tags-kept }}\r\n      run: |\r\n        python clean-except.py\r\n\r\n',
            'hk-package-clean-untagged/action.yml': '# Copyright (C) 2022 - 2026 ANSYS, Inc. and/or its affiliates.\r\n# SPDX-License-Identifier: MIT\r\n#\r\n#\r\n# Permission is hereby granted, free of charge, to any person obtaining a copy\r\n# of this software and associated documentation files (the "Software"), to deal\r\n# in the Software without restriction, including without limitation the rights\r\n# to use, copy, modify, merge, publish, distribute, sublicense, and/or sell\r\n# copies of the Software, and to permit persons to whom the Software is\r\n# furnished to do so, subject to the following conditions:\r\n#\r\n# The above copyright notice and this permission notice shall be included in all\r\n# copies or substantial portions of the Software.\r\n#\r\n# THE SOFTWARE IS PROVIDED "AS IS", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR\r\n# IMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,\r\n# FITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE\r\n# AUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER\r\n# LIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,\r\n# OUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN THE\r\n# SOFTWARE.\r\n\r\nname: "Clean untagged package versions."\r\ndescription: "Action cleaning up untagged package versions published at ghcr.io."\r\n\r\ninputs:\r\n  package-name:\r\n    description: "Package name."\r\n    required: true\r\n    type: string\r\n  token:\r\n    description: "Token with package deletion permissions."\r\n    required: true\r\n    type: string\r\n  package-org:\r\n    description: "Organization where packages are published."\r\n    required: false\r\n    default: \'ansys\'\r\n    type: string\r\n  allow-last-days:\r\n    description: "Avoid removing the last N days images: e.g. \'2\'."\r\n    required: false\r\n    default: \'\'\r\n    type: string\r\n  python-version:\r\n    description: \'Desired Python version.\'\r\n    default: \'3.11\'\r\n    required: false\r\n    type: string\r\n  use-uv:\r\n    description: |\r\n      Whether to use uv as the default package manager instead of pip. Default value is ``true``.\r\n    default: true\r\n    required: false\r\n    type: boolean\r\n\r\nruns:\r\n  using: "composite"\r\n  steps:\r\n\r\n    - name: "Set up Python ${{ inputs.python-version }}"\r\n      uses: ansys/actions/_setup-python@main\r\n      with:\r\n        python-version: ${{ inputs.python-version }}\r\n        use-cache: false\r\n        provision-uv: ${{ inputs.use-uv }}\r\n        prune-uv-cache: true\r\n\r\n    - name: "Install ghapi"\r\n      shell: bash\r\n      env:\r\n        INSTALL_COMMAND: ${{ inputs.use-uv == \'true\' && \'uv pip install --no-managed-python --system\' || \'python -m pip install\' }}\r\n      run: |\r\n\r\n        ${INSTALL_COMMAND} --upgrade pip\r\n        ${INSTALL_COMMAND} ghapi\r\n\r\n    - name: "Clone script"\r\n      shell: bash\r\n      env:\r\n        INPUT_TOKEN: ${{ inputs.token }}\r\n      run: |\r\n        cat > clean-untagged.py << \'EOF\'\r\n\r\n        from datetime import datetime, timedelta\r\n        import os\r\n\r\n        from ghapi.all import GhApi\r\n        from ghapi.core import print_summary\r\n        from ghapi.page import paged\r\n\r\n        PACKAGE_TIME_FORMAT = "%Y-%m-%dT%H:%M:%SZ"\r\n\r\n        org_str = os.environ.get("PACKAGE_ORG")\r\n        pck_str = os.environ.get("PACKAGE_NAME")\r\n        last_days_str = os.environ.get("ALLOW_LAST_DAYS")\r\n\r\n        last_days = int(last_days_str) if last_days_str != "" else None\r\n        if last_days:\r\n            delete_before_date = datetime.now() - timedelta(days=last_days)\r\n\r\n        input_token = os.getenv("PACKAGE_DELETION_TOKEN") or os.getenv("INPUT_TOKEN")\r\n        if not input_token:\r\n            raise ValueError("No token provided. Please set the \'PACKAGE_DELETION_TOKEN\' environment variable or \'INPUT_TOKEN\'.")\r\n        api = GhApi(debug=print_summary, token=input_token)\r\n\r\n        paged_packages = paged(\r\n            api.packages.get_all_package_versions_for_package_owned_by_org,\r\n            org=org_str,\r\n            package_name=pck_str,\r\n            package_type="container",\r\n            state="active",\r\n            per_page=100,\r\n        )\r\n\r\n        # Loop over all pages\r\n        for page in paged_packages:\r\n            for package in page:\r\n                # If keeping last days is requested, then check\r\n                if (\r\n                    last_days\r\n                    and datetime.strptime(package.created_at, PACKAGE_TIME_FORMAT).timestamp()\r\n                    > delete_before_date.timestamp()\r\n                ):\r\n                    continue\r\n\r\n                # Check if the given package has no tags\r\n                package_tags = package.metadata.container.tags\r\n\r\n                # If no tags were found... delete it!\r\n                if not package_tags:\r\n                    print(f"Deleting package: {package}")\r\n                    api.packages.delete_package_version_for_org(\r\n                        org=org_str,\r\n                        package_name=pck_str,\r\n                        package_type="container",\r\n                        package_version_id=package["id"],\r\n                    )\r\n\r\n        EOF\r\n        cat clean-untagged.py\r\n\r\n    - name: "Run package cleanup"\r\n      shell: bash\r\n      env:\r\n        ALLOW_LAST_DAYS: ${{ inputs.allow-last-days }}\r\n        PACKAGE_ORG: ${{ inputs.package-org }}\r\n        PACKAGE_NAME: ${{ inputs.package-name }}\r\n        PACKAGE_DELETION_TOKEN: ${{ inputs.token }}\r\n      run: |\r\n        python clean-untagged.py\r\n\r\n',
        }
